// Handle focus mode — forward keys directly to the agent's PTY
if m.state == stateFocusAgent {
	// Ctrl+Space exits focus mode
	if msg.String() == "ctrl+@" {
		m.exitFocusMode()
		return m, tea.RequestWindowSize
	}

	// Ctrl+Up/Down: cycle through active instances (wrapping) while staying in focus mode
	if msg.Code == tea.KeyUp && msg.Mod.Contains(tea.ModCtrl) || msg.Code == tea.KeyDown && msg.Mod.Contains(tea.ModCtrl) {
		if msg.Code == tea.KeyUp && msg.Mod.Contains(tea.ModCtrl) {
			m.nav.CyclePrevActive()
		} else {
			m.nav.CycleNextActive()
		}
		cmd := m.instanceChanged()
		// Re-enter focus mode for the newly selected instance
		focusCmd := m.enterFocusMode()
		return m, tea.Batch(cmd, focusCmd)

// non-dismissed action results. "adopt" and "attach" do dismiss the overlay.
func (b *TmuxBrowserOverlay) HandleKey(msg tea.KeyPressMsg) Result {
	switch msg.Code {
	case tea.KeyEscape:
		if b.searchQuery != "" {
			b.searchQuery = ""
			b.applyFilter()
			return Result{}
		}
		return Result{Dismissed: true}
	case tea.KeyEnter:
		if len(b.filtered) > 0 {
			return Result{Dismissed: true, Action: "attach"}
		}
		return Result{}
	case tea.KeyUp:
		if b.selectedIdx > 0 {
			b.selectedIdx--
		}
		return Result{}

// Run is the main entrypoint into the application.
func Run(ctx context.Context, program string, autoYes bool) error {
	// Set the terminal's default background to the theme base color so every
	// ANSI reset and unstyled cell falls back to #232136 instead of black.
	restore := ui.SetTerminalBackground("#232136")
	defer restore()
	defer sentrypkg.RecoverPanic()

	zone.NewGlobal()
	h := newHome(ctx, program, autoYes)
	defer h.embeddedServer.Stop()
	defer h.auditLogger.Close()
	if h.permissionStore != nil {
		defer h.permissionStore.Close()
	}
	p := tea.NewProgram(h)
	_, err := p.Run()
	return err
}

// permissionActionLabels maps selectedIdx to the action string returned by HandleKey.
var permissionActionLabels = []string{"allow_once", "allow_always", "reject"}

// HandleKey implements Overlay. Processes a key event and returns a Result.
func (p *PermissionOverlay) HandleKey(msg tea.KeyPressMsg) Result {
	switch msg.Code {
	case tea.KeyLeft:
		if p.selectedIdx > 0 {
			p.selectedIdx--
		}
		return Result{}
	case tea.KeyRight:
		if p.selectedIdx < len(permissionChoiceLabels)-1 {
			p.selectedIdx++
		}
		return Result{}
	case tea.KeyEnter:
		p.confirmed = true
		action := permissionActionLabels[p.selectedIdx]
		return Result{Dismissed: true, Submitted: true, Action: action}

